      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0].metric).toBe('orders');
      expect(trends[0].value).toBe(2);
      expect(trends[0].timestamp).toEqual(new Date('2024-03-01'));
      expect(trends[1].value).toBe(1);
      expect(trends[1].timestamp).toEqual(new Date('2024-03-15'));
    });

    it('should return revenue trends', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'order-1', total: 20, createdAt: new Date('2024-03-01') }));
      orderRepo.save(makeOrder({ id: 'order-2', total: 30, createdAt: new Date('2024-03-01') }));
      orderRepo.save(makeOrder({ id: 'order-3', total: 50, createdAt: new Date('2024-03-15') }));

      const trends = service.getTrends('revenue', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0].metric).toBe('revenue');
      expect(trends[0].value).toBe(50);
      expect(trends[1].value).toBe(50);
    });

    it('should filter orders by date range', () => {
      userRepo.save(makeUser());
      orderRepo.save(makeOrder({ id: 'order-1', createdAt: new Date('2024-01-15') }));
      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-03-15') }));
      orderRepo.save(makeOrder({ id: 'order-3', createdAt: new Date('2024-06-15') }));

      const trends = service.getTrends('orders', new Date('2024-02-01'), new Date('2024-04-30'));

      expect(trends).toHaveLength(1);
      expect(trends[0].value).toBe(1);
